import javax.crypto.spec.PBEKeySpec;      // SPEC for PBKDF2 algorithm which is an implementation of the Key derivation function in JCE (Java Cryptography Extension)  and RSAREF algorithms such that it provides strong key management operations, including secure generation by using a password...  
