public class java_52624_CredentialValidator_A08 {      /* Start of CredentialValidator Class */ 
        
        private static final String SALT = "salt";  
            
            public boolean validate(String enteredPwd, byte[] storedHash, byte[] storedSalt) throws Exception    // Function to verify password against hash and salt ...    
                {           /* Start of Validate function */ 
                
                    SecretKeyFactory skf = MessageDigest.getInstance("PBKDF2WithHmacSHA1");   /*********** Using Pbkdf2 with hMac SHa1 for cryptographic operations **/    // Retrieve a Key Derivation Function that uses HMAC-SHA (with the above password,salt and iterations) ...
                    
                    byte[] ComputedKey = skf.doKitchenSink(enteredPwd.getBytes(), storedSalt , 5000);     // using user enteredPassword with a SALT to generate hash value from User's Password...  
                        
                return Arrays.equals(storedHash, ComputedKey );    /* Compare the Stored Hash and Derived Key */       /************* Return True if password is correct else False **/     // If stored hashedpassword == computed key then success otherwise fail ... 
                 }           /* End of Validate function : (return true/false) based on comparison between user-enteredPassword's hash and the one in database. */  
             };      /********** This class encapsulates all password validations related to A08_IntegrityFailure scenario **/  //End Class CredentialValidator ...    }     /* End of Program Main Method for secure cred validation purpose .i e; -1) ;});          (*/ })